CREATE PROC [dbo].[TR_TONKHO_THANHPHAM_MINUS]
( 
	@order_id       nvarchar(50), 
	@order_number   nvarchar(200), 
	@cust_po_number nvarchar(200), 
	@product_code   nvarchar(200), 
	@quantity       int
)
AS
BEGIN
    DECLARE @SOLUONG int;
    DECLARE @product_name nvarchar(max);
    DECLARE @range nvarchar(200);
    DECLARE @uom nvarchar(50);

    SELECT @SOLUONG = quantity
    FROM   tr_tonkho_thanhpham
    WHERE  order_number = @order_number
		 --AND ISNULL(cust_po_number, '') = @cust_po_number
		 AND product_code = @product_code

    IF @SOLUONG IS NULL
    BEGIN
	   DECLARE @quantity2 int;

	   SELECT @product_name = tensp
		   , @range = hehang
		   , @uom = dvt
	   FROM   tr_sanpham WITH(NOLOCK)
	   WHERE  masp = @product_code

	   SET @quantity2 = 0 - @quantity;
	   EXEC TR_TONKHO_THANHPHAM_Insert @order_number, 
								@cust_po_number, 
								@product_code, 
								@product_name, 
								@range, 
								@uom, 
								@quantity2;
    END
    ELSE
    BEGIN
	   UPDATE tr_tonkho_thanhpham
		SET  quantity = @SOLUONG - @quantity
	   WHERE  order_number = @order_number
		    --AND cust_po_number = @cust_po_number
		    AND product_code = @product_code
    END


    DECLARE @SHIP_QTY int;

    SELECT @SHIP_QTY = ship_qty
    FROM   tr_order_detail
    WHERE  id = @order_id

    UPDATE tr_order_detail
	 SET  ship_qty = @SHIP_QTY + @quantity,
	   Finished = CASE WHEN (@SHIP_QTY + @quantity) >= order_qty THEN 1 ELSE 0 END
    WHERE  id = @order_id
